const express = require('express');
const crypto = require('crypto');

const app = express();
const port = 3000;

// PREMBLY_API_KEY is required for signature verification
const PREMBLY_API_KEY = process.env.PREMBLY_API_KEY;

// Middleware to capture the raw request body for HMAC verification
app.use(express.json({
  verify: (req, res, buf) => {
    req.rawBody = buf;
  }
}));

/**
 * Middleware for verifying Prembly webhook signature
 */
const verifyPremblySignature = (req, res, next) => {
  const signature = req.headers['x-prembly-signature'];

  if (!signature) {
    return res.status(401).json({ error: 'Invalid signature' });
  }

  if (!PREMBLY_API_KEY) {
    console.error('PREMBLY_API_KEY environment variable is not set');
    return res.status(500).json({ error: 'Internal server error' });
  }

  if (!req.rawBody) {
    return res.status(401).json({ error: 'Invalid signature' });
  }

  // Compute HMAC-SHA256 (Base64 encoded) of the raw request body using the API key
  const hmac = crypto.createHmac('sha256', PREMBLY_API_KEY);
  hmac.update(req.rawBody);
  const computedSignature = hmac.digest('base64');

  // Compare computed signature with the one from the header
  if (computedSignature === signature) {
    next();
  } else {
    res.status(401).json({ error: 'Invalid signature' });
  }
};

/**
 * Webhook endpoint
 */
app.post('/webhook', verifyPremblySignature, (req, res) => {
  console.log('Received valid webhook:', req.body);

  // Prembly expects a 200 OK response on success
  res.status(200).json({ status: 'success' });
});

app.listen(port, () => {
  console.log(`Prembly webhook server listening at http://localhost:${port}`);
});

